# A/B Testing Setup Runbook > Test Setup in Code > 2. Assign Users to Variants

### 2. Assign Users to Variants

Implement deterministic assignment using user ID hash:

```javascript
// backend/controllers/checkoutController.js
import crypto from 'crypto'

export async function getCheckoutVariant(req, res) {
  try {
    const userId = req.user._id.toString()
    const testId = "checkout-v2-2024-04"

    // Get test config
    const test = await ABTest.findOne({ testId })
    if (!test || test.status !== 'running') {
      return res.json({ variant: 'control' })  // Default to control if test not active
    }

    // Deterministic assignment using hash (same user always gets same variant)
    const hash = crypto.createHash('md5')
      .update(`${testId}${userId}`)
      .digest('hex')
    const hashValue = parseInt(hash.substring(0, 8), 16) % 100

    let assignedVariant = 'control'
    if (hashValue < 50) {
      assignedVariant = 'control'
    } else {
      assignedVariant = 'variant'
    }

    // Log exposure event for analytics
    await logAnalyticsEvent({
      userId,
      testId,
      variant: assignedVariant,
      eventType: 'exposed',
      timestamp: new Date()
    })

    res.json({ variant: assignedVariant })
  } catch (error) {
    res.status(500).json({ error: error.message })
  }
}
```

# A/B Testing Setup Runbook > Test Setup in Code > 3. Render Different UI Based on Variant

### 3. Render Different UI Based on Variant

In frontend component:

```javascript
// frontend/src/screens/CheckoutScreen.jsx
import { useEffect, useState } from 'react'

export default function CheckoutScreen() {
  const [variant, setVariant] = useState('control')

  useEffect(() => {
    // Fetch assigned variant from backend
    fetch('/api/tests/checkout-variant')
      .then(res => res.json())
      .then(data => setVariant(data.variant))
  }, [])

  if (variant === 'control') {
    return (
      <div className="checkout-control">
        <h2>Shipping Address</h2>
        {/* Old 3-step flow */}
      </div>
    )
  } else {
    return (
      <div className="checkout-variant">
        <h2>Shipping & Payment</h2>
        {/* New 2-step flow */}
      </div>
    )
  }
}
```

# A/B Testing Setup Runbook > Tracking Analytics Events

## Tracking Analytics Events

Log key events for both control and variant users:

```javascript
// backend/utils/analytics.js
export async function logAnalyticsEvent(event) {
  const { userId, testId, variant, eventType, metadata } = event

  await AnalyticsEvent.insertOne({
    userId,
    testId,
    variant,
    eventType,        // 'exposed', 'checkout_started', 'checkout_completed', 'order_placed'
    metadata: {
      orderValue: metadata?.orderValue || null,
      cartItemCount: metadata?.cartItemCount || null,
      timestamp: metadata?.timestamp || new Date()
    }
  })
}

// Usage in order controller
export async function createOrder(req, res) {
  try {
    const testId = "checkout-v2-2024-04"
    const test = await ABTest.findOne({ testId, status: 'running' })

    if (test) {
      const variant = await assignVariant(req.user._id, testId)

      // Log conversion event
      await logAnalyticsEvent({
        userId: req.user._id,
        testId,
        variant,
        eventType: 'order_placed',
        metadata: {
          orderValue: req.body.totalPrice,
          cartItemCount: req.body.orderItems.length,
          timestamp: new Date()
        }
      })
    }

    // ... rest of order creation logic
    res.status(201).json(order)
  } catch (error) {
    res.status(500).json({ error: error.message })
  }
}
```

## Running the Test

### Phase 1: Validation (Days 1–2)

Check that:
- Users are split 50/50 between variants.
- Variant B renders correctly.
- No errors in logs.

**Query to verify split:**

```javascript
db.analyticsEvents.aggregate([
  {
    $match: {
      testId: "checkout-v2-2024-04",
      eventType: "exposed"
    }
  },
  {
    $group: {
      _id: "$variant",
      count: { $sum: 1 }
    }
  }
])

// Expected output:
// { _id: "control", count: 2500 }
// { _id: "variant", count: 2487 }
```

# Database Seed and Reset Runbook > Seeding Custom Data

## Seeding Custom Data

If you want to seed custom test data (e.g., 100 products, specific categories):

### Step 1: Create Seed File

```javascript
// backend/seedCustom.js
import mongoose from 'mongoose'
import dotenv from 'dotenv'
import colors from 'colors'
import User from './models/userModel.js'
import Product from './models/productModel.js'
import connectDB from './config/db.js'

dotenv.config()
connectDB()

const customProducts = [
  {
    name: "Custom Product 1",
    brand: "TestBrand",
    category: "TestCategory",
    description: "A custom test product",
    price: 99.99,
    countInStock: 20,
    rating: 0,
    numReviews: 0,
  },
  // ... more products
]

const importCustomData = async () => {
  try {
    const adminUser = await User.findOne({ email: 'admin@example.com' })

    const productsWithUser = customProducts.map(p => ({
      ...p,
      user: adminUser._id
    }))

    await Product.insertMany(productsWithUser)
    console.log(`Imported ${productsWithUser.length} custom products`.green.inverse)
    process.exit()
  } catch (error) {
    console.error(`${error}`.red.inverse)
    process.exit(1)
  }
}

importCustomData()
```

### Step 2: Add NPM Script

Edit `package.json`:

```json
{
  "scripts": {
    "data:import-custom": "node backend/seedCustom.js"
  }
}
```

### Step 3: Run Custom Seed

```bash
npm run data:import-custom
```

# Database Seed and Reset Runbook > Seeding with Production-Like Data

## Seeding with Production-Like Data

For staging/performance testing, you might want realistic data volumes:

```javascript
// backend/seedLarge.js
// Generate 1000 products with varied attributes

const generateLargeDataset = async (productCount = 1000) => {
  const products = []
  const categories = ['Electronics', 'Books', 'Clothing', 'Sports', 'Home']
  const brands = ['Brand A', 'Brand B', 'Brand C', 'Brand D']

  for (let i = 1; i <= productCount; i++) {
    products.push({
      name: `Product ${i}`,
      brand: brands[i % brands.length],
      category: categories[i % categories.length],
      description: `Description for product ${i}`,
      price: Math.random() * 500 + 10,  // Random price $10–$510
      countInStock: Math.floor(Math.random() * 100),
      rating: Math.random() * 5,
      numReviews: Math.floor(Math.random() * 50),
    })
  }

  const adminUser = await User.findOne({ email: 'admin@example.com' })
  const productsWithUser = products.map(p => ({ ...p, user: adminUser._id }))

  await Product.insertMany(productsWithUser)
  console.log(`Created ${productCount} products for load testing`.green.inverse)
  process.exit()
}

generateLargeDataset(1000)
```

# Feature Flag Toggle Runbook > Architecture Overview

**Purpose:** Safely roll out new features to production via feature flags with zero-downtime, progressive canary deployment, and instant kill switch.  
**Audience:** Product managers, backend engineers, release managers.  
**Duration:** Varies by rollout strategy (5 min to 2 hours for full rollout).  
**Scope:** Feature flags are conditionals in code that enable/disable code paths without redeployment.

## Architecture Overview

Feature flags are stored in MongoDB and checked at runtime. Example:

```javascript
// backend/controllers/productController.js
const featureFlags = await FeatureFlag.findOne({ key: 'new-search-filter' })

if (featureFlags?.enabled) {
  // New filtered search logic
  products = await Product.find(filterQuery).populate('reviews')
} else {
  // Old search logic
  products = await Product.find(filterQuery)
}
```

### Feature Flag Schema (MongoDB)

```javascript
{
  key: "new-search-filter",           // Unique identifier
  enabled: false,                     // Global on/off
  rolloutPercentage: 0,               // 0-100%, overrides enabled if set
  targetUserIds: [],                  // Whitelist specific users
  excludeUserIds: [],                 // Blacklist specific users
  startDate: ISODate("2024-04-15"),   // When to enable
  endDate: ISODate("2024-05-15"),     // When to auto-disable
  metadata: {
    description: "New product search with advanced filtering",
    owner: "product-team",
    metrics: { exposure: 5000, conversions: 150 }
  }
}
```

# Feature Flag Toggle Runbook > Pre-Rollout Preparation > 1. Code Implementation

## Pre-Rollout Preparation

### 1. Code Implementation

Ensure code has both old and new paths protected by the flag:

```javascript
export async function getProducts(req, res) {
  try {
    const flag = await FeatureFlag.findOne({ key: 'new-search-filter' })
    const shouldEnableNewSearch = evaluateFlag(flag, req.user._id)

    if (shouldEnableNewSearch) {
      // New implementation
      const results = await searchNewAlgorithm(req.query)
      res.json(results)
    } else {
      // Old implementation (stable fallback)
      const results = await searchOldAlgorithm(req.query)
      res.json(results)
    }
  } catch (error) {
    res.status(500).json({ error: error.message })
  }
}

function evaluateFlag(flag, userId) {
  if (!flag) return false
  if (flag.excludeUserIds.includes(userId)) return false
  if (flag.targetUserIds.length > 0) return flag.targetUserIds.includes(userId)
  if (flag.rolloutPercentage > 0) {
    const hash = hashFunction(userId) % 100
    return hash < flag.rolloutPercentage
  }
  return flag.enabled
}
```

### 2. Local Testing

Test both code paths locally before deploying:

```bash
# Terminal 1: Start app with flag disabled
NODE_ENV=development npm run dev

# Terminal 2: Test old path
curl "http://localhost:5001/api/products?sort=price" | jq .

# Terminal 3: Manually enable flag in MongoDB (local)
# Use MongoDB compass or CLI:
# db.featureflags.updateOne(
#   { key: 'new-search-filter' },
#   { $set: { enabled: true } }
# )

# Test new path (should see different results)
curl "http://localhost:5001/api/products?sort=price" | jq .
```

# Feature Flag Toggle Runbook > Rollout Phases > Phase 1: Internal Testing (0% → 5%)

## Rollout Phases

### Phase 1: Internal Testing (0% → 5%)

Enable flag for your team and key stakeholders only:

```javascript
db.featureflags.updateOne(
  { key: "new-search-filter" },
  {
    $set: {
      rolloutPercentage: 5,
      targetUserIds: ["user123", "user456"],  // Your test accounts
      excludeUserIds: []
    }
  }
)
```

**Duration:** 1–2 hours.  
**Monitoring:** Watch error logs, response times, and user behavior in analytics.

```bash
# Check logs
heroku logs --app proshop-prod --tail | grep "new-search-filter"

# Example: Look for errors
heroku logs --app proshop-prod --grep "Error"
```

**Success criteria:**
- Zero errors in logs.
- P95 latency unchanged.
- Test users report expected behavior.

### Phase 2: Canary – Beta Users (5% → 25%)

Gradually expose to a wider audience:

```javascript
db.featureflags.updateOne(
  { key: "new-search-filter" },
  { $set: { rolloutPercentage: 25 } }
)
```

**Duration:** 2–4 hours.  
**Metrics to track:**
- Error rate (aim for 0%).
- Average response time (should not increase >10%).
- Conversion rate (aim for no decrease).
- User complaints in support channels.

**Query conversion rate (example):**

```javascript
// Pseudo-query: count orders created after rollout
db.orders.aggregate([
  {
    $match: {
      createdAt: { $gte: ISODate("2024-04-15T10:00:00Z") }
    }
  },
  {
    $group: {
      _id: null,
      totalOrders: { $sum: 1 },
      totalRevenue: { $sum: "$totalPrice" }
    }
  }
])
```
